noncompliant:
@Configuration
class AppConfig {
  @Bean
  public Service service1() { return new Service(); }
  @Bean
  public Service service2() { return new Service(); } // Both beans have the same type and default name
}

compliant:
@Configuration
class AppConfig {
  @Bean(name = "service1")
  public Service service1() { return new Service(); }
  @Bean(name = "service2")
  public Service service2() { return new Service(); }
}
